//生成两个List 1.一个订单List 一个出库List
const deliveryList=[];
const orderList=new Set();
const order=[];
// 创建一个对象用于记录每个订单号对应的总金额
const orderAmounts = {};
for(const item of $input.all()){
  if(item.json['订单状态']==='待寄回'&&item.json['订单编号']&&item.json['追溯ID']){
    const { '订单编号': id, '支付金额': amount } = item.json;

  // 判断订单号是否已经存在于Set中
  if (orderList.has(id)) {
    // 如果订单号已存在，累加金额
    orderAmounts[id] += amount;
  } else {
    // 如果订单号不存在，将订单号添加到Set中，并记录初始金额
    orderList.add(id);
    orderAmounts[id] = amount;
  }

    deliveryList.push({
      order_number:item.json['订单编号'],
      sku_code:item.json['料号'],
      retroid:item.json['追溯ID'],
      price:item.json['支付金额'],
      watchType:item.json['产品名称'].slice(0,3)
    })
  }
}
for(let key in orderAmounts){
  if(orderAmounts[key]){
    order.push({
    order_number:key,
    amounts:orderAmounts[key]
  })
  }
}
return {
  order:order,
  delivery:deliveryList,
  snList:deliveryList.map(e=>{
    return `'${e.retroid}'`
  }).join()
}

